#include <stdio.h>

struct Point {
    int x;
    int y;
};

struct Config {
    int width;
    int height;
    int fullscreen;
    int vsync;
    int fps_limit;
};

void print_point(struct Point p) {
    printf("(%d, %d)\n", p.x, p.y);
}

int main(void) {
    /* Positional initialization */
    struct Point p1 = {10, 20};
    print_point(p1); /* (10, 20) */

    /* C99 designated initializers */
    struct Point p2 = {.y = 50, .x = 30}; /* order doesn't matter */
    print_point(p2); /* (30, 50) */

    /* Partial initialization: unspecified fields = 0 */
    struct Point p3 = {.x = 7};
    print_point(p3); /* (7, 0) */

    /* Zero initialization */
    struct Point p4 = {0};
    print_point(p4); /* (0, 0) */

    /* Designated initializers shine with large structs */
    struct Config cfg = {
        .width = 1920,
        .height = 1080,
        .fullscreen = 1,
        /* vsync and fps_limit default to 0 */
    };
    printf("Config: %dx%d fullscreen=%d vsync=%d\n",
           cfg.width, cfg.height, cfg.fullscreen, cfg.vsync);

    /* Compound literal (C99) -- useful for passing to functions */
    print_point((struct Point){.x = 100, .y = 200}); /* (100, 200) */

    return 0;
}

