#include <stdio.h>
#include <stdlib.h>

/* Self-referential structure for singly linked list */
struct Node {
    int data;
    struct Node *next;
};

struct Node *create_node(int data) {
    struct Node *n = malloc(sizeof(*n));
    if (n) {
        n->data = data;
        n->next = NULL;
    }
    return n;
}

void push_front(struct Node **head, int data) {
    struct Node *new_node = create_node(data);
    if (new_node) {
        new_node->next = *head;
        *head = new_node;
    }
}

void print_list(const struct Node *head) {
    const struct Node *curr = head;
    while (curr) {
        printf("%d -> ", curr->data);
        curr = curr->next;
    }
    printf("NULL\n");
}

void free_list(struct Node *head) {
    while (head) {
        struct Node *tmp = head;
        head = head->next;
        free(tmp);
    }
}

int main(void) {
    struct Node *list = NULL;
    push_front(&list, 30);
    push_front(&list, 20);
    push_front(&list, 10);

    print_list(list); /* 10 -> 20 -> 30 -> NULL */

    free_list(list);
    return 0;
}

