#include <stdio.h>
#include <stdint.h>

/* Normal struct with padding */
struct Normal {
    char type;     /* 1 byte */
    /* 3 bytes padding */
    int length;    /* 4 bytes */
    char flags;    /* 1 byte */
    /* 3 bytes padding */
};
/* Total: 12 bytes */

/* Packed struct -- no padding */
#pragma pack(push, 1)
struct PacketHeader {
    uint8_t type;     /* 1 byte */
    uint32_t length;  /* 4 bytes */
    uint8_t flags;    /* 1 byte */
};
#pragma pack(pop)
/* Total: 6 bytes */

/* Alternative GCC/Clang syntax */
struct __attribute__((packed)) GCCPacked {
    uint8_t type;
    uint32_t length;
    uint8_t flags;
};
/* Total: 6 bytes */

int main(void) {
    printf("Normal size:       %zu\n", sizeof(struct Normal));       /* 12 */
    printf("PacketHeader size: %zu\n", sizeof(struct PacketHeader)); /* 6 */
    printf("GCCPacked size:    %zu\n", sizeof(struct GCCPacked));    /* 6 */

    /* Use packed struct for binary protocol */
    struct PacketHeader pkt = {.type = 0x01, .length = 1024, .flags = 0x80};
    printf("Packet: type=0x%02x length=%u flags=0x%02x\n",
           pkt.type, pkt.length, pkt.flags);

    /* Accessing packed members is safe through the struct itself */
    /* But taking address of misaligned member is dangerous: */
    /* uint32_t *p = &pkt.length; */  /* WARNING: misaligned pointer! */

    return 0;
}

