#include <stdio.h>
#include <stdint.h>

/* Basic union */
union Number {
    int i;
    float f;
    char bytes[4];
};

/* Type punning: view float bits as integer */
void show_float_bits(float f) {
    union { float f; uint32_t i; } u;
    u.f = f;
    printf("float %.2f = bits 0x%08X\n", f, u.i);
}

/* Practical: network byte order conversion helper */
union IPv4 {
    uint32_t addr;
    uint8_t octets[4];
};

int main(void) {
    /* Union basics */
    union Number n;
    printf("sizeof(union Number) = %zu\n", sizeof(n)); /* 4 */

    n.i = 42;
    printf("As int: %d\n", n.i);     /* 42 */

    n.f = 3.14f;
    printf("As float: %.2f\n", n.f); /* 3.14 */
    /* n.i is now invalid (overwritten by f) */

    /* Type punning (well-defined in C99) */
    show_float_bits(3.14f);   /* float 3.14 = bits 0x4048F5C3 */
    show_float_bits(0.0f);    /* float 0.00 = bits 0x00000000 */
    show_float_bits(-1.0f);   /* float -1.00 = bits 0xBF800000 */

    /* IP address manipulation */
    union IPv4 ip;
    ip.octets[0] = 192;
    ip.octets[1] = 168;
    ip.octets[2] = 1;
    ip.octets[3] = 100;
    printf("IP: %u.%u.%u.%u (raw: 0x%08X)\n",
           ip.octets[0], ip.octets[1], ip.octets[2], ip.octets[3],
           ip.addr);

    return 0;
}

