#include <stdio.h>

enum Direction { NORTH, EAST, SOUTH, WEST, NUM_DIRECTIONS };

enum HttpStatus {
    HTTP_OK = 200,
    HTTP_NOT_FOUND = 404,
    HTTP_INTERNAL_ERROR = 500
};

/* Enum as bit flags */
enum Permissions {
    PERM_READ = 1,    /* 001 */
    PERM_WRITE = 2,   /* 010 */
    PERM_EXEC = 4     /* 100 */
};

const char *direction_name(enum Direction d) {
    static const char *names[] = {"North", "East", "South", "West"};
    if (d >= 0 && d < NUM_DIRECTIONS) return names[d];
    return "Unknown";
}

int main(void) {
    /* Basic enum usage */
    enum Direction d = EAST;
    printf("%s (value=%d)\n", direction_name(d), d); /* East (value=1) */

    /* Enum in switch */
    enum HttpStatus status = HTTP_OK;
    switch (status) {
        case HTTP_OK:             printf("200 OK\n"); break;
        case HTTP_NOT_FOUND:      printf("404 Not Found\n"); break;
        case HTTP_INTERNAL_ERROR: printf("500 Error\n"); break;
    }

    /* Enum as bit flags */
    int perms = PERM_READ | PERM_WRITE;
    if (perms & PERM_READ)  printf("Can read\n");
    if (perms & PERM_WRITE) printf("Can write\n");
    if (perms & PERM_EXEC)  printf("Can execute\n");

    /* Enum constants are int */
    printf("sizeof(NORTH) = %zu\n", sizeof(NORTH));     /* sizeof(int) */
    printf("sizeof(enum Direction) = %zu\n", sizeof(enum Direction));

    /* NUM_DIRECTIONS trick for array sizing */
    const char *labels[NUM_DIRECTIONS] = {"N", "E", "S", "W"};
    for (int i = 0; i < NUM_DIRECTIONS; i++)
        printf("%s ", labels[i]);
    printf("\n");

    return 0;
}

