#include <stdio.h>
#include <stdlib.h>
#include <string.h>

struct Person {
    char name[50];  /* array: copied by value */
    int age;        /* primitive: copied by value */
    char *email;    /* pointer: only address copied (shallow!) */
};

/* Deep copy function */
struct Person person_clone(const struct Person *src) {
    struct Person copy = *src; /* start with shallow copy */
    if (src->email) {
        copy.email = malloc(strlen(src->email) + 1);
        if (copy.email) {
            strcpy(copy.email, src->email);
        }
    }
    return copy;
}

void person_free(struct Person *p) {
    free(p->email);
    p->email = NULL;
}

int main(void) {
    struct Person alice = {
        .name = "Alice",
        .age = 30,
        .email = malloc(20)
    };
    strcpy(alice.email, "alice@example.com");

    /* Shallow copy: name array copied, but email pointer shared! */
    struct Person shallow = alice;
    printf("Shallow: %s, %s\n", shallow.name, shallow.email);
    printf("Same pointer? %s\n",
           (alice.email == shallow.email) ? "YES (danger!)" : "no");

    /* Deep copy: email has its own memory */
    struct Person deep = person_clone(&alice);
    printf("Deep: %s, %s\n", deep.name, deep.email);
    printf("Same pointer? %s\n",
           (alice.email == deep.email) ? "yes" : "NO (safe)");

    /* Clean up -- only free once for shared pointer! */
    person_free(&alice);
    /* shallow.email is now dangling! */
    person_free(&deep); /* safe: independent copy */

    return 0;
}

