struct Matrix {
    double data[100]; /* 800 bytes -- expensive to copy */
};

struct Point {
    int x, y; /* 8 bytes -- cheap to copy */
};

/* Pass small struct by value -- simple and safe */
struct Point offset_point(struct Point p, int dx, int dy) {
    p.x += dx; /* modifies local copy only */
    p.y += dy;
    return p;  /* return by value is fine for small structs */
}

/* Pass large struct by const pointer -- efficient, read-only */
double matrix_trace(const struct Matrix *m) {
    double sum = 0;
    for (int i = 0; i < 10; i++) {
        sum += m->data[i * 10 + i]; /* diagonal elements */
    }
    return sum;
}

