#include <stdio.h>

/* Pattern 1: Anonymous struct with typedef */
typedef struct {
    double x, y;
} Vec2;

/* Pattern 2: Named struct with typedef */
typedef struct Color {
    unsigned char r, g, b, a;
} Color;

/* Pattern 3: Self-referential struct */
typedef struct Node {
    int data;
    struct Node *next; /* must use 'struct Node', not 'Node' here */
} Node;

/* Pattern 4: Forward declaration for opaque pointer */
typedef struct Engine Engine; /* forward declaration */
/* struct Engine is defined in the .c file */

void print_vec(Vec2 v) {
    printf("(%.1f, %.1f)\n", v.x, v.y);
}

int main(void) {
    /* Using typedef -- no 'struct' keyword needed */
    Vec2 pos = {3.0, 4.0};
    print_vec(pos); /* (3.0, 4.0) */

    Color red = {255, 0, 0, 255};
    printf("Red: (%u, %u, %u)\n", red.r, red.g, red.b);

    /* Named struct can use either form */
    struct Color blue = {0, 0, 255, 255}; /* also valid */
    Color green = {0, 255, 0, 255};
    printf("Blue: (%u, %u, %u)\n", blue.r, blue.g, blue.b);
    printf("Green: (%u, %u, %u)\n", green.r, green.g, green.b);

    /* Self-referential */
    Node a = {10, NULL};
    Node b = {20, &a};
    printf("%d -> %d\n", b.data, b.next->data); /* 20 -> 10 */

    return 0;
}

#include <stdio.h>

typedef struct Node {
    int data;
    struct Node *next; /* must use 'struct Node' inside */
} Node;

int main(void) {
    Node a = {10, NULL};
    Node b = {20, &a};
    printf("%d -> %d\n", b.data, b.next->data); /* 20 -> 10 */
    return 0;
}

