#include <stdio.h>

/* Tagged union with anonymous union -- clean access */
typedef struct {
    enum { TYPE_INT, TYPE_FLOAT, TYPE_STRING } type;
    union {
        int i;
        float f;
        const char *s;
    }; /* anonymous union: access i/f/s directly */
} Value;

void print_value(const Value *v) {
    switch (v->type) {
        case TYPE_INT:    printf("int: %d\n", v->i); break;
        case TYPE_FLOAT:  printf("float: %.2f\n", v->f); break;
        case TYPE_STRING: printf("string: %s\n", v->s); break;
    }
}

/* Vector with dual access patterns */
typedef union {
    struct { float x, y, z; }; /* anonymous struct */
    float data[3];              /* array access */
} Vec3;

int main(void) {
    /* Tagged union with anonymous union */
    Value v1 = {.type = TYPE_INT, .i = 42};
    Value v2 = {.type = TYPE_FLOAT, .f = 3.14f};
    Value v3 = {.type = TYPE_STRING, .s = "hello"};

    print_value(&v1); /* int: 42 */
    print_value(&v2); /* float: 3.14 */
    print_value(&v3); /* string: hello */

    /* No 'u.' prefix needed -- direct access */
    printf("Direct access: %d\n", v1.i); /* 42 */

    /* Vector with anonymous struct */
    Vec3 v = {.x = 1.0f, .y = 2.0f, .z = 3.0f};
    printf("Named: (%.0f, %.0f, %.0f)\n", v.x, v.y, v.z);
    printf("Array: (%.0f, %.0f, %.0f)\n", v.data[0], v.data[1], v.data[2]);

    /* Both access the same memory */
    v.data[1] = 99.0f;
    printf("y after data[1]=99: %.0f\n", v.y); /* 99 */

    return 0;
}

#include <stdio.h>

typedef struct {
    int type;
    union { int i; float f; }; /* anonymous union */
} Value;

int main(void) {
    Value v = {.type = 0, .i = 42};
    printf("%d\n", v.i); /* 42 -- direct access, no prefix */
    return 0;
}

