#include <stdio.h>
#include <string.h>

struct Point {
    int x;
    int y;
};

struct Person {
    char name[50];
    int age;
    char *email; /* pointer member */
};

/* Member-by-member comparison (correct) */
int point_equal(const struct Point *a, const struct Point *b) {
    return a->x == b->x && a->y == b->y;
}

/* For structs with strings and pointers */
int person_equal(const struct Person *a, const struct Person *b) {
    return strcmp(a->name, b->name) == 0
        && a->age == b->age
        && (a->email == b->email || /* both NULL or same ptr */
            (a->email && b->email && strcmp(a->email, b->email) == 0));
}

int main(void) {
    /* struct Point: no padding (same-sized members), memcmp OK here */
    struct Point p1 = {10, 20};
    struct Point p2 = {10, 20};
    struct Point p3 = {10, 30};

    /* This would NOT compile: */
    /* if (p1 == p2) printf("equal\n"); */

    /* Member-by-member (recommended) */
    printf("p1 == p2: %s\n", point_equal(&p1, &p2) ? "yes" : "no"); /* yes */
    printf("p1 == p3: %s\n", point_equal(&p1, &p3) ? "yes" : "no"); /* no */

    /* memcmp -- works here because struct Point has no padding */
    printf("memcmp p1==p2: %s\n",
           memcmp(&p1, &p2, sizeof(p1)) == 0 ? "yes" : "no"); /* yes */

    /* Danger: struct with padding */
    struct { char a; int b; } x, y;
    x.a = 1; x.b = 2;
    y.a = 1; y.b = 2;
    /* memcmp may fail because padding bytes differ! */
    printf("memcmp with padding: %s\n",
           memcmp(&x, &y, sizeof(x)) == 0 ? "equal" : "may differ");

    return 0;
}

#include <stdio.h>

struct Point { int x, y; };

int point_eq(const struct Point *a, const struct Point *b) {
    return a->x == b->x && a->y == b->y;
}

int main(void) {
    struct Point p1 = {10, 20}, p2 = {10, 20};
    /* if (p1 == p2) -- COMPILE ERROR */
    printf("%s\n", point_eq(&p1, &p2) ? "equal" : "not equal"); /* equal */
    return 0;
}

answers.explanation:
A **tagged union** (discriminated union) combines a union with an enum tag that identifies which union member is currently active. This is C's equivalent of sum types / variant types found in other languages.

**Pattern:**
```c
typedef struct {
    enum { TYPE_A, TYPE_B, TYPE_C } tag;
    union {
        TypeA a;
        TypeB b;
        TypeC c;
    };
} Variant;
```

The tag field tracks which union member is valid. All operations must check the tag before accessing union members.

**Real-world uses:**
- JSON values (null, bool, number, string, array, object)
- Abstract syntax tree (AST) nodes
- Event systems (different event types with different data)
- Configuration values (int, float, string settings)
- Interpreter values (different runtime types)

**Safety:** The programmer must ensure the tag matches the active union member. Accessing the wrong member is undefined behavior (or at least a logic bug).

answers.pseudo_code:
1. Define enum for possible types
2. Define union with one member per type
3. Combine in a struct: tag + union
4. Every access must switch on the tag

struct Value {
    enum { INT, FLOAT, STRING } type;  /* tag */
    union { int i; float f; char *s; }; /* data */
};

Construct: v.type = INT; v.i = 42;
Access:    if (v.type == INT) use(v.i);
           else if (v.type == STRING) use(v.s);

