#include <stdio.h>
#include <stdlib.h>
#include <string.h>

/* JSON-like value using tagged union */
typedef enum {
    VAL_NULL,
    VAL_BOOL,
    VAL_INT,
    VAL_FLOAT,
    VAL_STRING
} ValueType;

typedef struct {
    ValueType type; /* discriminant / tag */
    union {
        int boolean;
        long integer;
        double floating;
        char *string;
    }; /* anonymous union (C11) */
} Value;

/* Constructor functions */
Value val_null(void) {
    return (Value){.type = VAL_NULL};
}

Value val_int(long v) {
    return (Value){.type = VAL_INT, .integer = v};
}

Value val_float(double v) {
    return (Value){.type = VAL_FLOAT, .floating = v};
}

Value val_string(const char *s) {
    Value v = {.type = VAL_STRING};
    v.string = malloc(strlen(s) + 1);
    if (v.string) strcpy(v.string, s);
    return v;
}

Value val_bool(int b) {
    return (Value){.type = VAL_BOOL, .boolean = b != 0};
}

/* Safe access: always check the tag */
void print_value(const Value *v) {
    switch (v->type) {
        case VAL_NULL:   printf("null"); break;
        case VAL_BOOL:   printf("%s", v->boolean ? "true" : "false"); break;
        case VAL_INT:    printf("%ld", v->integer); break;
        case VAL_FLOAT:  printf("%.2f", v->floating); break;
        case VAL_STRING: printf("\"%s\"", v->string); break;
    }
    printf("\n");
}

void free_value(Value *v) {
    if (v->type == VAL_STRING) {
        free(v->string);
        v->string = NULL;
    }
    v->type = VAL_NULL;
}

int main(void) {
    Value values[] = {
        val_null(),
        val_bool(1),
        val_int(42),
        val_float(3.14),
        val_string("hello")
    };
    int n = sizeof(values) / sizeof(values[0]);

    for (int i = 0; i < n; i++) {
        printf("[%d] ", i);
        print_value(&values[i]);
    }

    /* Cleanup: only strings need freeing */
    for (int i = 0; i < n; i++) {
        free_value(&values[i]);
    }

    /* sizeof: union uses space of largest member */
    printf("sizeof(Value) = %zu\n", sizeof(Value));

    return 0;
}

#include <stdio.h>

typedef struct {
    enum { T_INT, T_FLOAT, T_STR } type;
    union { int i; float f; const char *s; };
} Value;

void print(const Value *v) {
    switch (v->type) {
        case T_INT:   printf("%d\n", v->i); break;
        case T_FLOAT: printf("%.2f\n", v->f); break;
        case T_STR:   printf("%s\n", v->s); break;
    }
}

int main(void) {
    Value v1 = {.type = T_INT, .i = 42};
    Value v2 = {.type = T_STR, .s = "hello"};
    print(&v1); /* 42 */
    print(&v2); /* hello */
    return 0;
}
